object AuthLogger {
    private const val TAG = "AuthLogger"

    fun logAuthAttempt(username: String?, method: String, success: Boolean, reason: String? = null) {
        val sanitizedUsername = username ?: "null"
        val status = if (success) "SUCCESS" else "FAILURE"
        val reasonText = reason?.let { " reason=$it" } ?: ""
        AppLogger.v(
            TAG,
            "Authentication attempt status=$status method=$method username=$sanitizedUsername$reasonText"
        )
    }

    fun logLogout(userId: String?, reason: String? = null) {
        AppLogger.v(
            TAG,
            "Logout userId=${userId ?: "null"} reason=${reason ?: "unspecified"}"
        )
    }

    fun logSessionState(userId: String?, state: String, details: String? = null) {
        AppLogger.v(
            TAG,
            "Session state userId=${userId ?: "null"} state=$state details=${details ?: "none"}"
        )
    }
}

object DatabaseLogger {
    private const val TAG = "DatabaseLogger"

    fun logQuery(
        sql: String,
