            throwable
        )
    }
}

class VerboseHttpLoggingInterceptor(
    private val logger: (String) -> Unit = { AppLogger.v("ApiLogger", it) }
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        logRequest(request)

        val startNs = System.nanoTime()
        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            logResponse(response, tookMs)
            response
        } catch (e: Exception) {
            AppLogger.e("ApiLogger", "HTTP call failed ${request.method} ${request.url}", e)
            throw e
        }
    }

    private fun logRequest(request: Request) {
        val requestBody = request.body
        val bodyString = requestBody?.let { bodyToString(it) } ?: "null"

        val headersBuilder = StringBuilder()
        for (i in 0 until request.headers.size) {
            headersBuilder.append(request.headers.name(i))
                .append(": ")
                .append(request.headers.value(i))
                .append("\n")
        }

        logger(
            buildString {
                append("HTTP REQUEST\n")
                append("url=").append(request.url).append("\n")
                append("method=").append(request.method).append("\n")
                append("headers=\n").append(headersBuilder.toString())
                append("body=").append(bodyString)
            }
        )
    }

    private fun logResponse(response: Response, tookMs: Long) {
        val responseBody = response.body
        val sourceBodyString = response.peekBody(Long.MAX_VALUE).string()

        val headersBuilder = StringBuilder()
        for (i in 0 until response.headers.size) {
            headersBuilder.append(response.headers.name(i))
                .append(": ")
                .append(response.headers.value(i))
                .append("\n")
        }

        logger(
            buildString {
                append("HTTP RESPONSE\n")
                append("url=").append(response.request.url).append("\n")
                append("code=").append(response.code).append("\n")
                append("message=").append(response.message).append("\n")
                append("durationMs=").append(tookMs).append("\n")
                append("headers=\n").append(headersBuilder.toString())
                append("body=").append(sourceBodyString)
            }
        )

        if (responseBody == null) {
            logger("HTTP RESPONSE BODY is null for url=${response.request.url}")
        }
    }

    private fun bodyToString(requestBody: RequestBody): String {
        return try {
            val buffer = Buffer()
            requestBody.writeTo(buffer)
            val charset: Charset = requestBody.contentType()?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            buffer.readString(charset)
        } catch (e: IOException) {
            "failed_to_read_request_body:${e.message}"
        }
    }
}

object ExceptionLogging {
    private const val TAG = "ExceptionLogger"

    fun installGlobalHandler() {
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            AppLogger.e(TAG, "Uncaught exception on thread=${thread.name}", throwable)
            defaultHandler?.uncaughtException(thread, throwable)
        }
    }

    fun logCaught(throwable: Throwable, context: String? = null) {
        AppLogger.e(
            TAG,
            "Caught exception context=${context ?: "none"}",
            throwable
        )
    }
}

object LoggingConfigurator {
    fun createOkHttpClient(baseClient: OkHttpClient? = null): OkHttpClient {
        val builder = (baseClient ?: OkHttpClient()).newBuilder()
        builder.addInterceptor(VerboseHttpLoggingInterceptor())
        builder.connectTimeout(30, TimeUnit.SECONDS)
        builder.readTimeout(30, TimeUnit.SECONDS)
        builder.writeTimeout(30, TimeUnit.SECONDS)
        return builder.build()
    }

    fun initialize(context: Context) {
        AppLogger.init(context)
        ExceptionLogging.installGlobalHandler()
        AppLogger.v("LoggingConfigurator", "Comprehensive logging configured")
    }
}

